import React from 'react';
import { Link, useNavigate } from 'react-router-dom';
import { useCart } from '../../context/CartContext';
import { useAuth } from '../../context/AuthContext';
import { orderService } from '../../services/orderService';
import toast from 'react-hot-toast';
import './Cart.css';

const PRODUCT_IMAGES = {
  'Grains': 'https://images.unsplash.com/photo-1586201375761-83865001e31c?w=100&q=70',
  'Dairy': 'https://images.unsplash.com/photo-1550583724-b2692b85b150?w=100&q=70',
  'Fruits': 'https://images.unsplash.com/photo-1610832958506-aa56368176cf?w=100&q=70',
  'default': 'https://images.unsplash.com/photo-1542838132-92c53300491e?w=100&q=70',
};

const Cart = () => {
  const { cart, cartItems, removeFromCart, loadCart } = useCart();
  const { user } = useAuth();
  const navigate = useNavigate();

  const subtotal = cartItems.reduce((sum, item) => sum + item.price * item.quantity, 0);
  const shipping = subtotal > 499 ? 0 : 49;
  const total = subtotal + shipping;

  const handleCheckout = async () => {
    try {
      await orderService.createOrder({
        userId: user.userId || user.user_id,
        deliveryAddress: user.address || 'Default Address',
        totalAmount: total,
        orderStatus: 'PLACED',
        paymentStatus: 'PENDING',
      });
      toast.success('🎉 Order placed successfully!');
      navigate('/orders');
    } catch {
      toast.error('Failed to place order');
    }
  };

  if (cartItems.length === 0) {
    return (
      <div className="cart-empty">
        <div className="empty-cart-icon">🛒</div>
        <h2>Your cart is empty</h2>
        <p>Looks like you haven't added anything yet</p>
        <Link to="/products" className="btn-shop-now">Start Shopping →</Link>
      </div>
    );
  }

  return (
    <div className="cart-page">
      <div className="cart-header">
        <h1>Your Cart</h1>
        <p>{cartItems.length} item{cartItems.length > 1 ? 's' : ''}</p>
      </div>
      <div className="cart-layout">
        <div className="cart-items-list">
          {cartItems.map((item) => {
            const imgKey = item.category || 'default';
            return (
              <div key={item.cartItemId || item.cart_item_id} className="cart-item-card">
                <img src={PRODUCT_IMAGES[imgKey] || PRODUCT_IMAGES.default} alt="Product" className="item-img" />
                <div className="item-details">
                  <h3>Product #{item.productId || item.product_id}</h3>
                  <p className="item-price">₹{(item.price).toFixed(2)} each</p>
                </div>
                <div className="item-quantity">
                  <span className="qty-badge">×{item.quantity}</span>
                </div>
                <div className="item-total">₹{(item.price * item.quantity).toFixed(2)}</div>
                <button className="item-remove" onClick={() => removeFromCart(item.cartItemId || item.cart_item_id)}>🗑️</button>
              </div>
            );
          })}
        </div>

        <div className="cart-summary">
          <h2>Order Summary</h2>
          <div className="summary-row">
            <span>Subtotal</span>
            <span>₹{subtotal.toFixed(2)}</span>
          </div>
          <div className="summary-row">
            <span>Shipping</span>
            <span className={shipping === 0 ? 'free' : ''}>{shipping === 0 ? 'FREE' : `₹${shipping}`}</span>
          </div>
          {shipping > 0 && (
            <div className="free-shipping-hint">
              Add ₹{(499 - subtotal).toFixed(2)} more for free shipping!
            </div>
          )}
          <div className="summary-divider"></div>
          <div className="summary-row total-row">
            <span>Total</span>
            <span>₹{total.toFixed(2)}</span>
          </div>
          <button className="checkout-btn" onClick={handleCheckout}>
            Place Order →
          </button>
          <Link to="/products" className="continue-shopping">← Continue Shopping</Link>
        </div>
      </div>
    </div>
  );
};

export default Cart;
